# Example task: Write a stdlib-only Go generic ParallelMap[T,R](items []T, workers int, fn func(T) R) []R that applies fn with at most `workers` goroutines and returns results in INPUT ORDER, race-free. Treat workers<=0 as 1. Use a jobs channel of indices, a sync.WaitGroup, and close the channel before Wait; each worker writes only its own result index so no mutex is needed.
```go
package pool

import "sync"

// ParallelMap applies fn to every item using at most workers goroutines and
// returns the results in input order. workers <= 0 is treated as 1. It is
// race-free: each worker writes only its own output slot, so no mutex guards
// the results slice.
func ParallelMap[T any, R any](items []T, workers int, fn func(T) R) []R {
	if workers < 1 {
		workers = 1
	}
	results := make([]R, len(items))
	jobs := make(chan int)

	var wg sync.WaitGroup
	for w := 0; w < workers; w++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			for i := range jobs {
				results[i] = fn(items[i])
			}
		}()
	}
	for i := range items {
		jobs <- i
	}
	close(jobs)
	wg.Wait()
	return results
}
```
# Example task: Write a package main HTTP handler that wires an http.ServeMux (standard library only, no third-party router) for GET /kv/{key} and PUT /kv/{key} backed by an in-memory store. Use the Go 1.22+ method+wildcard route patterns and r.PathValue. PUT returns 201 Created, GET returns the value (200) or 404 if absent. Expose newMux(s *Store) *http.ServeMux.
```go
package main

import (
	"io"
	"net/http"
	"sync"
)

type Store struct {
	mu sync.RWMutex
	m  map[string]string
}

func NewStore() *Store { return &Store{m: make(map[string]string)} }

func (s *Store) Get(key string) (string, bool) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	v, ok := s.m[key]
	return v, ok
}

func (s *Store) Set(key, value string) {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.m[key] = value
}

// newMux wires routes with the Go 1.22+ method+wildcard ServeMux patterns —
// no third-party router. r.PathValue extracts the {key} segment.
func newMux(s *Store) *http.ServeMux {
	mux := http.NewServeMux()
	mux.HandleFunc("GET /kv/{key}", func(w http.ResponseWriter, r *http.Request) {
		v, ok := s.Get(r.PathValue("key"))
		if !ok {
			http.Error(w, "not found", http.StatusNotFound)
			return
		}
		w.Header().Set("Content-Type", "text/plain")
		io.WriteString(w, v)
	})
	mux.HandleFunc("PUT /kv/{key}", func(w http.ResponseWriter, r *http.Request) {
		body, err := io.ReadAll(r.Body)
		if err != nil {
			http.Error(w, "bad body", http.StatusBadRequest)
			return
		}
		s.Set(r.PathValue("key"), string(body))
		w.WriteHeader(http.StatusCreated)
	})
	return mux
}

func main() {
	http.ListenAndServe(":8080", newMux(NewStore()))
}
```

