# Example task: Write the canonical layered-backend service package (standard library only): TaskService depending on BOTH a Store interface and an EventEnqueuer seam, constructed with NewTaskService(store, enqueuer) — constructors take every dependency explicitly. Create validates (ErrInvalid via errors.Is on bad status/missing fields), stores (ErrExists passthrough on duplicate ID), and enqueues one task.created event ONLY after success. List(limit int) returns at most limit tasks sorted by ID, limit <= 0 returns all. Unique IDs via strconv.Itoa.
```go
// Package main is the canonical layered-backend service: a TaskService that
// depends on BOTH a Store and an outbound EventEnqueuer seam — constructors in
// real backends take every dependency explicitly: NewTaskService(store, enq).
package main

import (
	"errors"
	"sort"
	"strconv"
	"sync"
)

var (
	ErrInvalid  = errors.New("invalid task")
	ErrExists   = errors.New("already exists")
	ErrNotFound = errors.New("not found")
)

type Task struct {
	ID     string
	Title  string
	Status string
}

type Event struct {
	Type   string
	TaskID string
}

// EventEnqueuer is the service's outbound seam; a worker satisfies it in
// production, a slice-backed fake records calls in tests.
type EventEnqueuer interface {
	Enqueue(e Event)
}

type Store interface {
	Create(t Task) error
	List() []Task
}

type MemStore struct {
	mu    sync.RWMutex
	items map[string]Task
}

func NewMemStore() *MemStore { return &MemStore{items: make(map[string]Task)} }

func (s *MemStore) Create(t Task) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	if _, dup := s.items[t.ID]; dup {
		return ErrExists
	}
	s.items[t.ID] = t
	return nil
}

func (s *MemStore) List() []Task {
	s.mu.RLock()
	defer s.mu.RUnlock()
	out := make([]Task, 0, len(s.items))
	for _, t := range s.items {
		out = append(out, t)
	}
	sort.Slice(out, func(i, j int) bool { return out[i].ID < out[j].ID })
	return out
}

// TaskService validates, delegates to the store, and emits an event ONLY
// after a successful create — a failed create never enqueues anything.
type TaskService struct {
	store Store
	enq   EventEnqueuer
}

// NewTaskService takes EVERY dependency the service uses — match the
// project's constructor signature exactly when calling it.
func NewTaskService(store Store, enq EventEnqueuer) *TaskService {
	return &TaskService{store: store, enq: enq}
}

func validStatus(s string) bool {
	return s == "todo" || s == "doing" || s == "done"
}

func (svc *TaskService) Create(t Task) (Task, error) {
	if t.ID == "" || t.Title == "" || !validStatus(t.Status) {
		return Task{}, ErrInvalid
	}
	if err := svc.store.Create(t); err != nil {
		return Task{}, err
	}
	svc.enq.Enqueue(Event{Type: "task.created", TaskID: t.ID})
	return t, nil
}

// List returns at most limit tasks sorted by ID; limit <= 0 returns all.
func (svc *TaskService) List(limit int) []Task {
	all := svc.store.List()
	if limit <= 0 || limit >= len(all) {
		return all
	}
	return all[:limit]
}

func main() {
	svc := NewTaskService(NewMemStore(), discard{})
	for i := 0; i < 3; i++ {
		id := strconv.Itoa(i) // UNIQUE ID per iteration — never string(i)
		_, _ = svc.Create(Task{ID: id, Title: "task " + id, Status: "todo"})
	}
	_ = svc.List(2)
}

type discard struct{}

func (discard) Enqueue(Event) {}
```
# Example task: Write a package main repository-pattern data layer (standard library only): a Store interface (Create/Get/List/Delete) over a User{ID,Name,Email} entity, plus a goroutine-safe in-memory MemStore backed by a map guarded by sync.RWMutex. Create returns a sentinel ErrExists on duplicate ID; Get/Delete return a sentinel ErrNotFound (matchable with errors.Is); List returns users sorted by ID for deterministic output. Add a compile-time `var _ Store = (*MemStore)(nil)` assertion.
```go
// Package main shows the repository pattern backends use for their data layer:
// a Store interface (so handlers/services depend on an abstraction, not a
// concrete DB) with a safe, concurrent in-memory implementation for tests and
// small deployments.
package main

import (
	"errors"
	"sort"
	"sync"
)

// ErrNotFound is returned when a lookup key is absent. Callers match it with
// errors.Is so the sentinel can be wrapped with context higher up.
var ErrNotFound = errors.New("not found")

// User is the stored entity.
type User struct {
	ID    string
	Name  string
	Email string
}

// Store is the abstraction the rest of the app depends on. A Postgres or SQLite
// implementation can be dropped in without touching callers.
type Store interface {
	Create(u User) error
	Get(id string) (User, error)
	List() []User
	Delete(id string) error
}

// ErrExists is returned by Create when the ID is already taken.
var ErrExists = errors.New("already exists")

// MemStore is a goroutine-safe in-memory Store.
type MemStore struct {
	mu    sync.RWMutex
	users map[string]User
}

// NewMemStore returns a ready-to-use empty store.
func NewMemStore() *MemStore {
	return &MemStore{users: make(map[string]User)}
}

func (s *MemStore) Create(u User) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	if _, ok := s.users[u.ID]; ok {
		return ErrExists
	}
	s.users[u.ID] = u
	return nil
}

func (s *MemStore) Get(id string) (User, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	u, ok := s.users[id]
	if !ok {
		return User{}, ErrNotFound
	}
	return u, nil
}

// List returns every user ordered by ID so results are deterministic.
func (s *MemStore) List() []User {
	s.mu.RLock()
	defer s.mu.RUnlock()
	out := make([]User, 0, len(s.users))
	for _, u := range s.users {
		out = append(out, u)
	}
	sort.Slice(out, func(i, j int) bool { return out[i].ID < out[j].ID })
	return out
}

func (s *MemStore) Delete(id string) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	if _, ok := s.users[id]; !ok {
		return ErrNotFound
	}
	delete(s.users, id)
	return nil
}

// compile-time proof MemStore satisfies Store.
var _ Store = (*MemStore)(nil)

func main() {}
```

