// fakeEnqueuer records every event so tests can assert exact call counts.
type fakeEnqueuer struct {
	Events []Event
}

func (f *fakeEnqueuer) Enqueue(e Event) { f.Events = append(f.Events, e) }

func TestCreateEnqueuesOnlyOnSuccess(t *testing.T) {
	cases := []struct {
		name       string
		task       Task
		wantErr    error
		wantEvents int // 1 for a valid create, 0 when validation fails
	}{
		{"valid task", Task{ID: "1", Title: "t1", Status: "todo"}, nil, 1},
		{"invalid status", Task{ID: "2", Title: "t2", Status: "bogus"}, ErrInvalid, 0},
		{"missing title", Task{ID: "3", Title: "", Status: "todo"}, ErrInvalid, 0},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			fake := &fakeEnqueuer{}
			svc := NewTaskService(NewMemStore(), fake) // fresh deps per row
			_, err := svc.Create(tc.task)
			if !errors.Is(err, tc.wantErr) {
				t.Fatalf("Create() error = %v, want %v", err, tc.wantErr)
			}
			if len(fake.Events) != tc.wantEvents {
				t.Fatalf("Enqueue() called %d times, want %d", len(fake.Events), tc.wantEvents)
			}
			if tc.wantEvents == 1 {
				// only inspect the event when the row expects one
				if fake.Events[0].Type != "task.created" || fake.Events[0].TaskID != tc.task.ID {
					t.Fatalf("Enqueue() got wrong event: %+v", fake.Events[0])
				}
			}
		})
	}
}

