# Example task: Write a package main stdlib-only JSON HTTP endpoint: POST /echo decodes a JSON body with encoding/json, validates it, and responds with JSON plus Content-Type application/json; 405 for non-POST, 400 for invalid/empty input, 200 on success. Expose newMux() *http.ServeMux.
```go
package main

import (
	"encoding/json"
	"net/http"
)

type echoRequest struct {
	Message string `json:"message"`
}

type echoResponse struct {
	Echo   string `json:"echo"`
	Length int    `json:"length"`
}

// newMux exposes POST /echo: decode a JSON body, validate it, and respond with
// JSON. Standard library only — encoding/json + net/http.
func newMux() *http.ServeMux {
	mux := http.NewServeMux()
	mux.HandleFunc("/echo", func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
			return
		}
		var req echoRequest
		if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
			http.Error(w, "invalid json", http.StatusBadRequest)
			return
		}
		if req.Message == "" {
			http.Error(w, "message required", http.StatusBadRequest)
			return
		}
		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusOK)
		json.NewEncoder(w).Encode(echoResponse{Echo: req.Message, Length: len(req.Message)})
	})
	return mux
}

func main() {
	http.ListenAndServe(":8080", newMux())
}
```
# Example task: Write a package main context-timeout HTTP handler (standard library only): a TimeoutHandler(timeout, work) that derives a deadline from r.Context() with context.WithTimeout, runs cancellable work (a select on time.After vs ctx.Done() that returns ctx.Err() when cancelled), and responds 504 Gateway Timeout when the deadline fires before the work finishes — never blocking the request forever. Write the result on success and always cancel the context.
```go
// Package main shows the context-timeout pattern a backend uses to bound slow
// dependencies: derive a deadline from the request context, run the work in a
// goroutine, and return 504 if the deadline fires before the work finishes —
// never blocking a request forever.
package main

import (
	"context"
	"net/http"
	"time"
)

// slowWork simulates a dependency (DB, upstream API) that honours cancellation:
// it returns early with ctx.Err() if the context is done first.
func slowWork(ctx context.Context, d time.Duration) (string, error) {
	select {
	case <-time.After(d):
		return "result", nil
	case <-ctx.Done():
		return "", ctx.Err()
	}
}

// TimeoutHandler bounds slowWork to `timeout`. On deadline it responds 504
// Gateway Timeout; on success it writes the result.
func TimeoutHandler(timeout time.Duration, work time.Duration) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		ctx, cancel := context.WithTimeout(r.Context(), timeout)
		defer cancel()

		res, err := slowWork(ctx, work)
		if err != nil {
			if ctx.Err() == context.DeadlineExceeded {
				http.Error(w, "request timed out", http.StatusGatewayTimeout)
				return
			}
			http.Error(w, "request cancelled", http.StatusRequestTimeout)
			return
		}
		_, _ = w.Write([]byte(res))
	}
}

func main() {
	mux := http.NewServeMux()
	// work (200ms) < timeout (500ms) -> succeeds.
	mux.Handle("GET /work", TimeoutHandler(500*time.Millisecond, 200*time.Millisecond))
	srv := &http.Server{Addr: ":8080", Handler: mux}
	_ = srv.ListenAndServe()
}
```

