package api

import (
	"log/slog"
	"net/http"
	"workapi/internal/auth"
	"workapi/internal/service"
)

// NewRouter registers method+pattern routes; ONLY the mutating routes are wrapped in auth (GET stays open),
// so tests of GET need no token while tests of POST always send one.
func NewRouter(svc service.TaskService, authToken string, logger *slog.Logger) http.Handler {
	mux := http.NewServeMux()
	taskHandler := NewTaskHandler(svc)

	mux.HandleFunc("POST /tasks", auth.TokenAuth(authToken)(http.HandlerFunc(taskHandler.Create)))
	mux.HandleFunc("GET /tasks", taskHandler.List)
	mux.HandleFunc("GET /tasks/{id}", taskHandler.Get)
	mux.HandleFunc("DELETE /tasks/{id}", auth.TokenAuth(authToken)(http.HandlerFunc(taskHandler.Delete)))

	mux.HandleFunc("GET /healthz", func(w http.ResponseWriter, r *http.Request) {
		writeJSON(w, http.StatusOK, "ok")
	})

	mux.HandleFunc("GET /readyz", func(w http.ResponseWriter, r *http.Request) {
		writeJSON(w, http.StatusOK, "ready")
	})

	return Chain(mux, Logging(logger), Recover(logger))
}


