# Example task: Write a package main table test (net/http/httptest) for a CRUD JSON router with auth on mutating routes: every POST row sends the valid Authorization: Bearer token (only the dedicated 401 row omits it), open GET routes need no token; decode the 201 response into the TYPED entity struct and the list response into a SLICE of the entity (never into a string); assert duplicate create returns 409 by posting the same id twice, and missing id returns 404. Use a doReq(t, handler, method, path, token, body) helper.
```go
// Package main tests a CRUD JSON router end to end. THE RULES:
//   - auth wraps the MUTATING routes, so every POST row sends the valid
//     Bearer token (only the dedicated 401 row omits it); open GET routes
//     need no token;
//   - decode JSON responses into TYPED values — the created entity decodes
//     into Item (an object), the list into []Item (an array); decoding into
//     a bare string is always wrong;
//   - a duplicate create asserts 409 by posting the SAME id twice.
package main

import (
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"
)

func doReq(t *testing.T, h http.Handler, method, path, token, body string) *httptest.ResponseRecorder {
	t.Helper()
	req := httptest.NewRequest(method, path, strings.NewReader(body))
	if token != "" {
		req.Header.Set("Authorization", "Bearer "+token)
	}
	rec := httptest.NewRecorder()
	h.ServeHTTP(rec, req)
	return rec
}

func TestRouterCRUD(t *testing.T) {
	h := NewRouter("secret")

	t.Run("POST without token is 401", func(t *testing.T) {
		rec := doReq(t, h, http.MethodPost, "/items", "", `{"id":"1","name":"a"}`)
		if rec.Code != http.StatusUnauthorized {
			t.Fatalf("status = %d, want 401", rec.Code)
		}
	})
	t.Run("POST valid with token is 201 and echoes the entity", func(t *testing.T) {
		rec := doReq(t, h, http.MethodPost, "/items", "secret", `{"id":"1","name":"a"}`)
		if rec.Code != http.StatusCreated {
			t.Fatalf("status = %d, want 201", rec.Code)
		}
		var got Item // decode into the TYPED entity, never a string
		if err := json.NewDecoder(rec.Body).Decode(&got); err != nil {
			t.Fatalf("decode created entity: %v", err)
		}
		if got.ID != "1" || got.Name != "a" {
			t.Fatalf("echo = %+v, want {1 a}", got)
		}
	})
	t.Run("duplicate id is 409", func(t *testing.T) {
		rec := doReq(t, h, http.MethodPost, "/items", "secret", `{"id":"1","name":"again"}`)
		if rec.Code != http.StatusConflict {
			t.Fatalf("status = %d, want 409", rec.Code)
		}
	})
	t.Run("GET list is 200 with a JSON array", func(t *testing.T) {
		rec := doReq(t, h, http.MethodGet, "/items", "", "")
		if rec.Code != http.StatusOK {
			t.Fatalf("status = %d, want 200", rec.Code)
		}
		var got []Item // an ARRAY decodes into a slice of the entity
		if err := json.NewDecoder(rec.Body).Decode(&got); err != nil {
			t.Fatalf("decode list: %v", err)
		}
		if len(got) != 1 || got[0].ID != "1" {
			t.Fatalf("list = %+v, want the created item", got)
		}
	})
	t.Run("GET by id 200 then missing id 404", func(t *testing.T) {
		if rec := doReq(t, h, http.MethodGet, "/items/1", "", ""); rec.Code != http.StatusOK {
			t.Fatalf("existing: status = %d, want 200", rec.Code)
		}
		if rec := doReq(t, h, http.MethodGet, "/items/zzz", "", ""); rec.Code != http.StatusNotFound {
			t.Fatalf("missing: status = %d, want 404", rec.Code)
		}
	})
}
