func TestWorkerDrains(t *testing.T) {
	logger := slog.New(slog.NewTextHandler(io.Discard, nil))
	w := NewWorker(8, logger)
	w.Start()

	var wg sync.WaitGroup
	for i := 0; i < 5; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			w.Enqueue(models.Event{Type: "task.created"})
		}()
	}
	wg.Wait()

	w.Stop()
	if got := w.Processed(); got != 5 {
		t.Errorf("Processed() = %d; want 5", got)
	}
}

func TestWorkerEnqueueConcurrency(t *testing.T) {
	logger := slog.New(slog.NewTextHandler(io.Discard, nil))
	w := NewWorker(8, logger)
	w.Start()

	var wg sync.WaitGroup
	var total int64
	for i := 0; i < 10; i++ {
		wg.Add(1)
		go func(i int) {
			defer wg.Done()
			w.Enqueue(models.Event{Type: "task.created"})
			atomic.AddInt64(&total, 1)
		}(i)
	}
	wg.Wait()

	w.Stop()
	if got := w.Processed(); got != 10 {
		t.Errorf("Processed() = %d; want 10", got)
	}
	if got := atomic.LoadInt64(&total); got != 10 {
		t.Errorf("Total enqueued = %d; want 10", got)
	}
}

