// Worker struct holds a buffered channel for events, a logger, a WaitGroup, and an atomic counter.
type Worker struct {
	ch        chan models.Event
	logger    *slog.Logger
	wg        sync.WaitGroup
	processed atomic.Int64
}

// NewWorker allocates a new Worker with a buffered channel of the given size and a logger.
func NewWorker(size int, logger *slog.Logger) *Worker {
	return &Worker{
		ch:     make(chan models.Event, size),
		logger: logger,
	}
}

// Start launches a goroutine to process events from the channel.
func (w *Worker) Start() {
	w.wg.Add(1)
	go func() {
		defer w.wg.Done()
		for e := range w.ch {
			w.process(e)
		}
	}()
}

// Enqueue sends an event to the worker's channel.
func (w *Worker) Enqueue(e models.Event) {
	w.ch <- e
}

// process increments the processed counter and logs the event type.
func (w *Worker) process(e models.Event) {
	w.processed.Add(1)
	w.logger.Debug("Processing event", "type", e.Type)
}

// Stop closes the channel and waits for all buffered events to be processed.
func (w *Worker) Stop() {
	close(w.ch)
	w.wg.Wait()
}

// Processed returns the number of events processed.
func (w *Worker) Processed() int64 {
	return w.processed.Load()
}

