	if err := t.Validate(); err != nil {
		return models.Task{}, err
	}
	if err := svc.store.CreateTask(ctx, t); err != nil {
		return models.Task{}, err
	}
	svc.events.Enqueue(models.Event{Type: "task.created", TaskID: t.ID})
