	w.Start()

	var wg sync.WaitGroup
	var total int64
	for i := 0; i < 10; i++ {
		wg.Add(1)
		go func(i int) {
			defer wg.Done()
			w.Enqueue(models.Event{Type: "task.created"})
			atomic.AddInt64(&total, 1)
		}(i)
	}
	wg.Wait()

	w.Stop()
	if got := w.Processed(); got != 10 {
